import{_ as t,c as i,a2 as a,o as n}from"./chunks/framework.CKjLqgBu.js";const u=JSON.parse('{"title":"Agentic Development Experience Sharing - Meeting Agenda","description":"","frontmatter":{"head":[]},"headers":[],"relativePath":"plans/2026-02-09-agentic-dev-experience-sharing-agenda.md","filePath":"plans/2026-02-09-agentic-dev-experience-sharing-agenda.md","lastUpdated":null}'),o={name:"plans/2026-02-09-agentic-dev-experience-sharing-agenda.md"};function l(r,e,s,c,d,h){return n(),i("div",null,e[0]||(e[0]=[a('<h1 id="agentic-development-experience-sharing-meeting-agenda" tabindex="-1">Agentic Development Experience Sharing - Meeting Agenda <a class="header-anchor" href="#agentic-development-experience-sharing-meeting-agenda" aria-label="Permalink to &quot;Agentic Development Experience Sharing - Meeting Agenda&quot;">​</a></h1><p><strong>Audience:</strong> RD Leads (beginner-level familiarity with AI coding tools) <strong>Duration:</strong> 30 minutes <strong>Goal:</strong> Inspire adoption through experience sharing <strong>Format:</strong> Presentation with open discussion at the end</p><hr><h2 id="agenda-overview" tabindex="-1">Agenda Overview <a class="header-anchor" href="#agenda-overview" aria-label="Permalink to &quot;Agenda Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Time</th><th>Section</th><th>Min</th></tr></thead><tbody><tr><td>0:00</td><td>Core Concepts</td><td>6</td></tr><tr><td>0:06</td><td>Toolchain</td><td>7</td></tr><tr><td>0:13</td><td>Workflow: How We Work Now</td><td>7</td></tr><tr><td>0:20</td><td>Agent Skills</td><td>4</td></tr><tr><td>0:24</td><td>Future Discussion Seeds</td><td>4</td></tr><tr><td>0:28</td><td>Open Floor</td><td>2</td></tr></tbody></table><hr><h2 id="_1-core-concepts-6-min" tabindex="-1">1. Core Concepts (6 min) <a class="header-anchor" href="#_1-core-concepts-6-min" aria-label="Permalink to &quot;1. Core Concepts (6 min)&quot;">​</a></h2><h3 id="context-engineering-3-min" tabindex="-1">Context Engineering (3 min) <a class="header-anchor" href="#context-engineering-3-min" aria-label="Permalink to &quot;Context Engineering (3 min)&quot;">​</a></h3><ul><li>The fundamental shift: coding skill matters less, <em>context preparation</em> matters more</li><li>What context engineering means in practice: <ul><li>CLAUDE.md as the project&#39;s &quot;brain&quot; -- coding standards, architecture decisions, conventions</li><li>Structured project context: API specs, design principles, coding style guides all become agent-readable inputs</li><li>The agent is only as good as the context you feed it</li></ul></li><li>Analogy: &quot;Context engineering is to agentic development what requirements engineering is to traditional development -- except now your audience includes machines&quot;</li></ul><h3 id="spec-driven-development-3-min" tabindex="-1">Spec-Driven Development (3 min) <a class="header-anchor" href="#spec-driven-development-3-min" aria-label="Permalink to &quot;Spec-Driven Development (3 min)&quot;">​</a></h3><ul><li>Specs are not documentation -- they are the <em>source of truth</em> that drives agent behavior</li><li>The chain: PRD &gt; OpenAPI spec &gt; UX spec &gt; Technical spec &gt; Agent executes against specs</li><li>Without specs, agents hallucinate. With specs, agents are predictable and auditable</li><li>Key message: &quot;Document as Code is not optional in agentic development -- it is the control mechanism&quot;</li></ul><p><strong>Suggested visuals:</strong></p><ul><li>Artifacts relationship diagram (Requirements &gt; Design &gt; Implementation chain)</li><li>Inter-org agent workflow architecture diagram</li></ul><hr><h2 id="_2-toolchain-7-min" tabindex="-1">2. Toolchain (7 min) <a class="header-anchor" href="#_2-toolchain-7-min" aria-label="Permalink to &quot;2. Toolchain (7 min)&quot;">​</a></h2><h3 id="openspec-2-5-min" tabindex="-1">OpenSpec (2.5 min) <a class="header-anchor" href="#openspec-2-5-min" aria-label="Permalink to &quot;OpenSpec (2.5 min)&quot;">​</a></h3><ul><li>Spec management system: proposals, categories, and detailed specs in a structured directory</li><li>Change proposals as the unit of work -- each proposal has design, tasks, and specs</li><li>Why RD leads care: reviewable, version-controlled spec layer <em>before</em> code is written</li><li>Agents read from OpenSpec to understand what to build; humans review OpenSpec to approve direction</li></ul><h3 id="hadlc-1-5-min" tabindex="-1">HADLC (1.5 min) <a class="header-anchor" href="#hadlc-1-5-min" aria-label="Permalink to &quot;HADLC (1.5 min)&quot;">​</a></h3><ul><li>The methodology that defines phase gates and artifacts</li><li>Tells you <em>when</em> humans must be involved vs <em>when</em> agents can operate autonomously</li><li>The five phases are guard rails, not bureaucracy</li></ul><h3 id="pencil-1-5-min" tabindex="-1">Pencil (1.5 min) <a class="header-anchor" href="#pencil-1-5-min" aria-label="Permalink to &quot;Pencil (1.5 min)&quot;">​</a></h3><ul><li>Design-to-code prototyping directly in the IDE (pencil.dev)</li><li>Closes the gap between UX spec and implementation</li><li>In agentic context: Pencil outputs feed into the agent&#39;s context as design reference, reducing interpretation errors</li></ul><h3 id="claude-code-1-5-min" tabindex="-1">Claude Code (1.5 min) <a class="header-anchor" href="#claude-code-1-5-min" aria-label="Permalink to &quot;Claude Code (1.5 min)&quot;">​</a></h3><ul><li>The agent runtime -- where skills, context, and specs come together</li><li>Not autocomplete (that&#39;s Copilot) -- an autonomous agent that reads project context, follows skills, and executes multi-step tasks</li><li>Skills, CLAUDE.md, slash commands as the interface between human intent and agent action</li></ul><p><strong>Suggested visual:</strong> Toolchain flow diagram: OpenSpec (specs) + Pencil (design) &gt; CLAUDE.md (context) &gt; Claude Code (execution) &gt; Code</p><hr><h2 id="_3-workflow-how-we-work-now-7-min" tabindex="-1">3. Workflow: How We Work Now (7 min) <a class="header-anchor" href="#_3-workflow-how-we-work-now-7-min" aria-label="Permalink to &quot;3. Workflow: How We Work Now (7 min)&quot;">​</a></h2><h3 id="opening-hook-1-min" tabindex="-1">Opening Hook (1 min) <a class="header-anchor" href="#opening-hook-1-min" aria-label="Permalink to &quot;Opening Hook (1 min)&quot;">​</a></h3><ul><li>Traditional dev: PM writes PRD &gt; Dev interprets &gt; Code &gt; Review &gt; Repeat</li><li>Problem: specs are ambiguous, agents can&#39;t work with vague intent, context is lost between phases</li></ul><h3 id="hadlc-overview-3-min" tabindex="-1">HADLC Overview (3 min) <a class="header-anchor" href="#hadlc-overview-3-min" aria-label="Permalink to &quot;HADLC Overview (3 min)&quot;">​</a></h3><ul><li>Five phases: Human-Centric &gt; Agent-Oriented &gt; Breakdown &gt; Construction &gt; Operations</li><li>Key insight: inception is split deliberately -- humans align on <em>what</em>, then translate into <em>agent-consumable</em> format</li><li>Work is spec-bounded, not time-bounded (Units/Tasks/Bolts vs Epics/Stories/Sprints)</li></ul><h3 id="spec-driven-hierarchy-2-min" tabindex="-1">Spec-Driven Hierarchy (2 min) <a class="header-anchor" href="#spec-driven-hierarchy-2-min" aria-label="Permalink to &quot;Spec-Driven Hierarchy (2 min)&quot;">​</a></h3><ul><li>Proposal &gt; Units (categories with spec.md) &gt; Tasks (endpoint/screen specs) &gt; Code</li><li>Traceability: any line of code traces back to a Task, Unit, and Proposal</li><li>This is how you maintain accountability when agents write code</li></ul><h3 id="current-state-1-min" tabindex="-1">Current State (1 min) <a class="header-anchor" href="#current-state-1-min" aria-label="Permalink to &quot;Current State (1 min)&quot;">​</a></h3><ul><li>Honest about where this is in practice: workflow is partly proven (showcase projects), partly still in development</li><li>Phase 5 (Operations) explicitly deferred</li></ul><p><strong>Suggested visual:</strong> HADLC five-phase flowchart with work level table</p><hr><h2 id="_4-agent-skills-4-min" tabindex="-1">4. Agent Skills (4 min) <a class="header-anchor" href="#_4-agent-skills-4-min" aria-label="Permalink to &quot;4. Agent Skills (4 min)&quot;">​</a></h2><h3 id="what-are-skills-1-5-min" tabindex="-1">What Are Skills? (1.5 min) <a class="header-anchor" href="#what-are-skills-1-5-min" aria-label="Permalink to &quot;What Are Skills? (1.5 min)&quot;">​</a></h3><ul><li>Structured documents that teach the agent how to perform a specific task consistently</li><li>Like functions for AI: reusable, documented, testable</li><li>Build once, invoke repeatedly via slash commands (e.g., <code>/slidev-presentation</code>, <code>/brainstorming</code>, <code>/code-review</code>)</li></ul><h3 id="skill-structure-1-min" tabindex="-1">Skill Structure (1 min) <a class="header-anchor" href="#skill-structure-1-min" aria-label="Permalink to &quot;Skill Structure (1 min)&quot;">​</a></h3><ul><li>Frontmatter (name + triggering conditions), workflow steps, reference material, quality guidelines</li><li>Key insight: the <code>description</code> field answers &quot;when should this activate&quot;, not &quot;what does it do&quot;</li><li>Skills live at different scopes: personal, project-level, shared via plugins</li></ul><h3 id="concrete-examples-1-5-min" tabindex="-1">Concrete Examples (1.5 min) <a class="header-anchor" href="#concrete-examples-1-5-min" aria-label="Permalink to &quot;Concrete Examples (1.5 min)&quot;">​</a></h3><ul><li><code>slidev-presentation</code> -- &quot;this presentation was generated using a skill&quot;</li><li><code>brainstorming</code> -- &quot;this agenda was drafted through a brainstorming skill session&quot;</li><li><code>code-review</code> / <code>systematic-debugging</code> -- development workflow skills</li><li>The meta point: skills encode <em>team knowledge</em>. When a senior engineer leaves, their practices survive as skills. When you onboard someone new, they get your team&#39;s skills on day one.</li></ul><p><strong>Suggested delivery:</strong> Show the slash command list or <code>.claude/</code> skill directory briefly</p><hr><h2 id="_5-future-discussion-seeds-4-min" tabindex="-1">5. Future Discussion Seeds (4 min) <a class="header-anchor" href="#_5-future-discussion-seeds-4-min" aria-label="Permalink to &quot;5. Future Discussion Seeds (4 min)&quot;">​</a></h2><h3 id="spec-management-at-scale-2-min" tabindex="-1">Spec Management at Scale (2 min) <a class="header-anchor" href="#spec-management-at-scale-2-min" aria-label="Permalink to &quot;Spec Management at Scale (2 min)&quot;">​</a></h3><ul><li>Current challenge: as projects grow, a single flat spec structure becomes unwieldy</li><li>Nested/hierarchical spec management -- multiple teams owning different spec areas</li><li>Questions for the audience: <ul><li>&quot;How would your team&#39;s existing requirements process map to spec-driven development?&quot;</li><li>&quot;Who owns the specs? PM? RD? Shared?&quot;</li><li>Cross-team spec dependencies -- when one team&#39;s API spec affects another team&#39;s tasks</li></ul></li></ul><h3 id="development-paradigm-shift-2-min" tabindex="-1">Development Paradigm Shift (2 min) <a class="header-anchor" href="#development-paradigm-shift-2-min" aria-label="Permalink to &quot;Development Paradigm Shift (2 min)&quot;">​</a></h3><ul><li>The role of the developer is changing: from &quot;writing code&quot; to &quot;curating context and reviewing agent output&quot;</li><li>Questions for RD leads to consider: <ul><li>How do you evaluate developer performance when agents write the code?</li><li>What does code review mean when the author is an agent?</li><li>Team skill building shifts from &quot;learn framework X&quot; to &quot;learn to engineer context for framework X&quot;</li></ul></li><li>Close with: &quot;These are not solved problems. We need each team&#39;s perspective to figure this out together.&quot;</li></ul><p><strong>Suggested delivery:</strong> Frame explicitly as &quot;questions, not answers&quot; -- make RD leads feel like collaborators, not an audience being lectured</p><hr><h2 id="preparation-checklist" tabindex="-1">Preparation Checklist <a class="header-anchor" href="#preparation-checklist" aria-label="Permalink to &quot;Preparation Checklist&quot;">​</a></h2><ul><li>[ ] Prepare HADLC five-phase diagram slide</li><li>[ ] Prepare artifacts relationship diagram</li><li>[ ] Prepare toolchain flow diagram</li><li>[ ] Screenshot of skill list / slash commands</li><li>[ ] Optional: 1-2 minute live demo of invoking a skill (if time permits)</li></ul><h2 id="reference-materials" tabindex="-1">Reference Materials <a class="header-anchor" href="#reference-materials" aria-label="Permalink to &quot;Reference Materials&quot;">​</a></h2><ul><li>Agentic Coding Workflow Proposal 2025 (<code>projects/proposals/agentic-coding-workflow-proposal-2025.md</code>)</li><li>AI-DLC Introduction slides (<code>presentations/ai-dlc-introduction/slides.md</code>)</li><li>Agentic Development Showcase slides (<code>presentations/agentic-development-showcase-2025/slides.md</code>)</li><li>Agent Workflow Architecture (<code>projects/agent-workflow-architecture.md</code>)</li><li>Agentic Development Alignment Kickoff (<code>presentations/agentic-development-alignment-kickoff/slides.md</code>)</li></ul>',56)]))}const p=t(o,[["render",l]]);export{u as __pageData,p as default};
